import React, { Component } from 'react'
import './App.css';
import NAV from '../Nav/nav'
import MAIN from '../Main/Main'
import CREATEWIND from '../CreatePostWindow/CreatePostWindow'
import POSTWINDOW from '../PostWindow/PostWindow'
import ACCOUNT from '../Account/Account'
import Post from '../../DATA/Post'
import PostLikes from '../../DATA/Post-likes'
import {
  BrowserRouter as Router,
  Routes,
  Route,
} from 'react-router-dom';

export default class App extends Component {


  constructor(props) {
    super(props)

    this.state = {
      listVisible: "",
    }
  }
  render() {
    const search = (e) => {
      this.setState({ listVisible: e })
    }
    const { listVisible } = this.state
    return (
      <div>
        <Router>
          <NAV search={search} />

          <Routes>
            <Route
              exact path="/"
              element={<MAIN listVisible={listVisible} tag={null} list={Post}/>}
            />
            <Route
              path="/posts/:id_post"
              element={<POSTWINDOW list={Post} listTwo={PostLikes}/>}
            />
            <Route
              path="/create-post"
              element={<CREATEWIND/>}
            />
            <Route
              path="/account"
              element={<ACCOUNT/>}
            />
            <Route
              path="*"
              element={<h1 className="error">ERROR404</h1>}
            />

          </Routes>

        </Router>
      </div>
    )
  }
}
